import requests

def get_pdb_structures_by_uniprot_id(uniprot_id):
    url = f"https://data.rcsb.org/rest/v1/search?query={{\"structure\":{{\"polymer_entity\":{{\"instance\":\"UNP\", \"identifiers\":\"{uniprot_id}\"}}}}}}"
    response = requests.get(url)
    if response.status_code == 200:
        return response.json()
    else:
        return None

uniprot_id = "P00519"  # Example UniProt ID for a human kinase
pdb_structures = get_pdb_structures_by_uniprot_id(uniprot_id)

if pdb_structures:
